function [nmbImg,imgLst] = fMspcDirLstV02(espcDir,nmbSht)% Function to get a list and number of images% for TREX magspec analysis%% [nmbImg,imgLst] = fMspcDirLstV02(espcDir,nmbSht)%% espcDir: a cell of directories to look for images% nmbSht: number of shots from trex logfile% nmbImg: number of images to go through% imgLst: image list (shot number)%% Kei Nakamura% Created on Monday, June 1st 2009.% Modified on Tuesday, April 13th 2010. %% ver.2: to follow the change in the directory structure (4 separate folders)%% mainimgExst0 = fMspcShtLstV01(espcDir{1},nmbSht,0);    % get a list for cam0imgExst2 = fMspcShtLstV01(espcDir{2},nmbSht,2);    % get a list for cam2imgExst3 = fMspcShtLstV01(espcDir{3},nmbSht,3);    % get a list for cam3imgExst4 = fMspcShtLstV01(espcDir{4},nmbSht,4);    % get a list for cam4imgExst = imgExst0.*imgExst2.*imgExst3.*imgExst4;nmbImg = sum(imgExst);aaa = [1:nmbSht]';imgExst = imgExst.*aaa;imgLst = find(imgExst~=0);
